// Extract and format log entry from webhook payload
const input = $json.body || $json;

const logEntry = {
  timestamp: new Date().toISOString(),
  conversation_id: input.conversation_id || 'unknown',
  agent_name: input.agent_name || 'unknown',
  caller_phone: input.caller_phone || '',
  duration_seconds: input.duration_seconds || 0,
  outcome: input.outcome || 'unknown',
  extracted_fields: JSON.stringify(input.extracted_fields || {}),
  errors: input.errors || ''
};

return { json: logEntry };
